var slideIndex = 0;
showSlides();
function showSlides() {
  var slides = document.getElementsByClassName("slide");
  var i;
  // Hide all slides
  for (i = 0; i < slides.length; i++) {
    slides[i].style.display = "none";
  }
  // Increment slide index
  slideIndex++;
  // Reset slide index if it exceeds the number of slides
  if (slideIndex > slides.length) {
    slideIndex = 1;
  }
  // Display the current slide
  slides[slideIndex - 1].style.display = "block";
  // Change slide every 3 seconds (adjust the duration as needed)
  setTimeout(showSlides, 3000);
}
function changeSlide(n) {
  slideIndex += n;
  showSlides();
}

const Home = () => {
  <div class="slideshow-container">
  <div class="slide">
    <img src="buildingsImage" alt="buildingsImage"></img>
  </div>
  <div class="slide">
    <img src="convoImage" alt="convoImage"></img>
  </div>
  <div class="slide">
    <img src="hmou" alt="hmou"></img>
  </div>
  
  <a class="prev" onclick="changeSlide(-1)">&#10094;</a>
  <a class="next" onclick="changeSlide(1)">&#10095;</a>
</div>

}


export default Home;
